@namespace Lumeo

<div class="@ContainerClass"
     role="img"
     aria-label="@AriaLabel"
     @attributes="AdditionalAttributes">
    @if (_error is not null)
    {
        <div class="text-xs text-muted-foreground">@_error</div>
    }
    else if (_modules.Count > 0)
    {
        <svg width="@SvgWidth" height="@SvgHeight"
             viewBox="0 0 @SvgWidth @SvgHeight"
             xmlns="http://www.w3.org/2000/svg"
             style="display:block;">
            @* Background *@
            <rect x="0" y="0" width="@SvgWidth" height="@SvgHeight"
                  fill="var(--color-@BackgroundColor, var(--color-background))" />
            @* Bars *@
            @{
                double xPos = QuietZone;
                foreach (var (width, isBar) in _modules)
                {
                    if (isBar)
                    {
                        <rect x="@xPos.ToString(System.Globalization.CultureInfo.InvariantCulture)"
                              y="0"
                              width="@width.ToString(System.Globalization.CultureInfo.InvariantCulture)"
                              height="@Height"
                              fill="var(--color-@Color, var(--color-foreground))" />
                    }
                    xPos += width;
                }
            }
            @* Text below bars rendered via foreignObject so we avoid Razor <text> conflict *@
            @if (ShowText)
            {
                <foreignObject x="0" y="@Height" width="@SvgWidth" height="20">
                    <div xmlns="http://www.w3.org/1999/xhtml"
                         style="@($"width:{SvgWidth}px;text-align:center;font-size:11px;font-family:monospace;color:var(--color-{Color});line-height:18px;")">
                        @_text
                    </div>
                </foreignObject>
            }
        </svg>
    }
</div>

@code {
    [Parameter] public string Value { get; set; } = "";
    [Parameter] public BarcodeFormat Format { get; set; } = BarcodeFormat.Code128;
    [Parameter] public int Height { get; set; } = 80;
    [Parameter] public double BarWidth { get; set; } = 2;
    [Parameter] public bool ShowText { get; set; } = true;
    [Parameter] public string Color { get; set; } = "foreground";
    [Parameter] public string BackgroundColor { get; set; } = "background";
    /// <summary>
    /// Fired after (re)encoding with the human-readable error message, or
    /// <c>null</c> when the value encoded successfully — a validation hook so a
    /// consumer can surface its own UI / gate a submit. (#291)
    /// </summary>
    [Parameter] public EventCallback<string?> OnError { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Quiet zone scales with the narrow-module width (the spec mandates ~10×
    // the narrow module, not a fixed pixel count) so a wide BarWidth keeps a
    // scanner-readable margin. (#291)
    private double QuietZone => 10 * BarWidth;

    private List<(double Width, bool IsBar)> _modules = new();

    // Canonical text content of the rendered barcode. Matches what a scanner
    // would decode: Value for Code 128, uppercased Value for Code 39, the
    // full 13 digits (incl. check digit) for EAN-13.
    private string _text = "";

    // Human-readable encoding error, or null when the barcode rendered.
    private string? _error;

    private int SvgWidth => (int)Math.Ceiling(_modules.Sum(m => m.Width) + QuietZone * 2);
    private int SvgHeight => ShowText ? Height + 20 : Height;

    private string ContainerClass => Cx.Merge("inline-block", Class);

    private string AriaLabel => _error is null
        ? $"Barcode: {_text}"
        : $"Barcode error: {_error}";

    private string? _lastError;
    private bool _reportedOnce;

    protected override async Task OnParametersSetAsync()
    {
        Rebuild();
        // Report the validation result once per change (including clearing to
        // null on a successful encode) — never on every unrelated param set.
        if (OnError.HasDelegate && (!_reportedOnce || _error != _lastError))
        {
            _reportedOnce = true;
            _lastError = _error;
            await OnError.InvokeAsync(_error);
        }
    }

    private void Rebuild()
    {
        _modules.Clear();
        _error = null;
        _text = Value;
        if (string.IsNullOrEmpty(Value)) return;
        try
        {
            bool[] bits;
            switch (Format)
            {
                case BarcodeFormat.Code39:
                    // Code 39 has no lowercase symbols; traditional Code 39
                    // behavior is to treat lowercase as uppercase, so we
                    // normalize (and display/announce the encoded uppercase
                    // text). Characters outside the 43-char set still fail.
                    _text = Value.ToUpperInvariant();
                    bits = Code39.Encode(_text);
                    break;
                case BarcodeFormat.EAN13:
                    _text = Ean13.Normalize(Value);
                    bits = Ean13.Encode(_text);
                    break;
                default:
                    bits = Code128B.Encode(Value);
                    break;
            }
            foreach (var bit in bits)
                _modules.Add((BarWidth, bit));
        }
        catch (Exception ex) when (ex is FormatException or ArgumentException)
        {
            // Surface the problem instead of silently rendering nothing:
            // show a small muted message and announce the error via aria-label.
            _modules.Clear();
            _text = Value;
            _error = ex.Message;
        }
    }

    public enum BarcodeFormat { Code128, Code39, EAN13 }

    // ─── Code 128B encoder ───────────────────────────────────────────────────
    // Code Set B covers ASCII 32–127. Each symbol is an 11-module pattern of
    // 3 bars and 3 spaces. The stop symbol is 13 modules (4 bars, 3 spaces + guard).
    // Reference: https://en.wikipedia.org/wiki/Code_128
    private static class Code128B
    {
        // 107 symbols (values 0–106) encoded as 11 bits (1=bar, 0=space).
        // Start Code B = symbol 104, Stop = special 13-module pattern.
        // Each entry is a string of 11 '0'/'1' chars: bar=1, space=0.
        private static readonly string[] Patterns =
        {
            "11011001100", // 0  — SP
            "11001101100", // 1  — !
            "11001100110", // 2  — "
            "10010011000", // 3  — #
            "10010001100", // 4  — $
            "10001001100", // 5  — %
            "10011001000", // 6  — &
            "10011000100", // 7  — '
            "10001100100", // 8  — (
            "11001001000", // 9  — )
            "11001000100", // 10 — *
            "11000100100", // 11 — +
            "10110011100", // 12 — ,
            "10011011100", // 13 — -
            "10011001110", // 14 — .
            "10111001100", // 15 — /
            "10011101100", // 16 — 0
            "10011100110", // 17 — 1
            "11001110010", // 18 — 2
            "11001011100", // 19 — 3
            "11001001110", // 20 — 4
            "11011100100", // 21 — 5
            "11001110100", // 22 — 6
            "11101101110", // 23 — 7
            "11101001100", // 24 — 8
            "11100101100", // 25 — 9
            "11100100110", // 26 — :
            "11101100100", // 27 — ;
            "11100110100", // 28 — <
            "11100110010", // 29 — =
            "11011011000", // 30 — >
            "11011000110", // 31 — ?
            "11000110110", // 32 — @
            "10100011000", // 33 — A
            "10001011000", // 34 — B
            "10001000110", // 35 — C
            "10110001000", // 36 — D
            "10001101000", // 37 — E
            "10001100010", // 38 — F
            "11010001000", // 39 — G
            "11000101000", // 40 — H
            "11000100010", // 41 — I
            "10110111000", // 42 — J
            "10110001110", // 43 — K
            "10001101110", // 44 — L
            "10111011000", // 45 — M
            "10111000110", // 46 — N
            "10001110110", // 47 — O
            "11101110110", // 48 — P
            "11010001110", // 49 — Q
            "11000101110", // 50 — R
            "11011101000", // 51 — S
            "11011100010", // 52 — T
            "11011101110", // 53 — U
            "11101011000", // 54 — V
            "11101000110", // 55 — W
            "11100010110", // 56 — X
            "11101101000", // 57 — Y
            "11101100010", // 58 — Z
            "11100011010", // 59 — [
            "11101111010", // 60 — \
            "11001000010", // 61 — ]
            "11110001010", // 62 — ^
            "10100110000", // 63 — _
            "10100001100", // 64 — `
            "10010110000", // 65 — a
            "10010000110", // 66 — b
            "10000101100", // 67 — c
            "10000100110", // 68 — d
            "10110010000", // 69 — e
            "10110000100", // 70 — f
            "10011010000", // 71 — g
            "10011000010", // 72 — h
            "10000110100", // 73 — i
            "10000110010", // 74 — j
            "11000010010", // 75 — k
            "11001010000", // 76 — l
            "11110111010", // 77 — m
            "11000010100", // 78 — n
            "10001111010", // 79 — o
            "10100111100", // 80 — p
            "10010111100", // 81 — q
            "10010011110", // 82 — r
            "10111100100", // 83 — s
            "10011110100", // 84 — t
            "10011110010", // 85 — u
            "11110100100", // 86 — v
            "11110010100", // 87 — w
            "11110010010", // 88 — x
            "11011011110", // 89 — y
            "11011110110", // 90 — z
            "11110110110", // 91 — {
            "10101111000", // 92 — |
            "10100011110", // 93 — }
            "10001011110", // 94 — ~
            "10111101000", // 95 — DEL (value 95 = symbol for DEL in Code B table)
            "10111100010", // 96
            "11110101000", // 97
            "11110100010", // 98
            "10111011110", // 99
            "10111101110", // 100
            "11101011110", // 101
            "11110101110", // 102 — FNC1
            "11010000100", // 103 — Start A
            "11010010000", // 104 — Start B
            "11010011100", // 105 — Start C
        };

        private const string StopPattern = "1100011101011";  // 13-module stop

        /// <summary>
        /// Encode a string (ASCII 32–126) as Code 128B and return the raw module
        /// bits: true = bar, false = space.
        /// </summary>
        public static bool[] Encode(string text)
        {
            // Validate: Code B supports ASCII 32–126
            foreach (char c in text)
                if (c < 32 || c > 126)
                    throw new FormatException($"Character '{c}' (0x{(int)c:X2}) is outside Code 128B range (ASCII 32-126).");

            var symbols = new List<int>();

            // Start Code B = symbol 104
            symbols.Add(104);

            int checksum = 104; // Start B symbol value
            int position = 1;

            foreach (char c in text)
            {
                // Code B: symbol value = ASCII value - 32
                int sym = c - 32;
                symbols.Add(sym);
                checksum += sym * position;
                position++;
            }

            // Check symbol
            symbols.Add(checksum % 103);

            // Build bit array
            var bits = new List<bool>();

            foreach (var sym in symbols)
            {
                var pattern = Patterns[sym];
                foreach (char bit in pattern)
                    bits.Add(bit == '1');
            }

            // Stop pattern (always bar-start, 13 modules)
            foreach (char bit in StopPattern)
                bits.Add(bit == '1');

            return bits.ToArray();
        }
    }

    // ─── Code 39 encoder ─────────────────────────────────────────────────────
    // 43 data characters: 0-9, A-Z, space, and - . $ / + %. Each symbol is 9
    // elements (5 bars / 4 spaces, alternating, starting and ending with a
    // bar) of which exactly 3 are wide. With wide = 2 narrow modules every
    // symbol is 12 modules; symbols are separated by a 1-module narrow space.
    // '*' is the start/stop symbol and is not valid as data. Standard Code 39
    // carries no check digit, so none is added.
    // Reference: https://en.wikipedia.org/wiki/Code_39
    private static class Code39
    {
        // Canonical Code 39 table as 12-module bit strings (bar=1, space=0),
        // i.e. the same intermediate representation Code128B emits.
        private static readonly Dictionary<char, string> Patterns = new()
        {
            ['0'] = "101001101101", ['1'] = "110100101011", ['2'] = "101100101011",
            ['3'] = "110110010101", ['4'] = "101001101011", ['5'] = "110100110101",
            ['6'] = "101100110101", ['7'] = "101001011011", ['8'] = "110100101101",
            ['9'] = "101100101101", ['A'] = "110101001011", ['B'] = "101101001011",
            ['C'] = "110110100101", ['D'] = "101011001011", ['E'] = "110101100101",
            ['F'] = "101101100101", ['G'] = "101010011011", ['H'] = "110101001101",
            ['I'] = "101101001101", ['J'] = "101011001101", ['K'] = "110101010011",
            ['L'] = "101101010011", ['M'] = "110110101001", ['N'] = "101011010011",
            ['O'] = "110101101001", ['P'] = "101101101001", ['Q'] = "101010110011",
            ['R'] = "110101011001", ['S'] = "101101011001", ['T'] = "101011011001",
            ['U'] = "110010101011", ['V'] = "100110101011", ['W'] = "110011010101",
            ['X'] = "100101101011", ['Y'] = "110010110101", ['Z'] = "100110110101",
            ['-'] = "100101011011", ['.'] = "110010101101", [' '] = "100110101101",
            ['$'] = "100100100101", ['/'] = "100100101001", ['+'] = "100101001001",
            ['%'] = "101001001001",
        };

        private const string StartStop = "100101101101"; // '*'

        /// <summary>
        /// Encode text (already uppercased by the caller) as Code 39 and return
        /// the raw module bits: true = bar, false = space.
        /// </summary>
        public static bool[] Encode(string text)
        {
            var bits = new List<bool>((text.Length + 2) * 12 + text.Length + 1);
            Append(bits, StartStop);
            foreach (char c in text)
            {
                if (!Patterns.TryGetValue(c, out var pattern))
                    throw new FormatException($"Character '{c}' is not valid for Code 39 (allowed: 0-9, A-Z, space, - . $ / + %).");
                bits.Add(false); // inter-character narrow space
                Append(bits, pattern);
            }
            bits.Add(false);
            Append(bits, StartStop);
            return bits.ToArray();
        }

        private static void Append(List<bool> bits, string pattern)
        {
            foreach (char bit in pattern)
                bits.Add(bit == '1');
        }
    }

    // ─── EAN-13 encoder ──────────────────────────────────────────────────────
    // 12 data digits + 1 check digit. Layout: start guard 101, six left
    // digits (7 modules each, L- or G-coded per the parity table selected by
    // the first digit), center guard 01010, six right digits (R-coded), end
    // guard 101 — always 95 modules in total.
    // Reference: https://en.wikipedia.org/wiki/International_Article_Number
    private static class Ean13
    {
        private static readonly string[] LCodes =
        {
            "0001101", "0011001", "0010011", "0111101", "0100011",
            "0110001", "0101111", "0111011", "0110111", "0001011",
        };

        private static readonly string[] GCodes =
        {
            "0100111", "0110011", "0011011", "0100001", "0011101",
            "0111001", "0000101", "0010001", "0001001", "0010111",
        };

        private static readonly string[] RCodes =
        {
            "1110010", "1100110", "1101100", "1000010", "1011100",
            "1001110", "1010000", "1000100", "1001000", "1110100",
        };

        // Parity (L/G) of the six left-group digits, indexed by the first digit.
        private static readonly string[] LeftParity =
        {
            "LLLLLL", "LLGLGG", "LLGGLG", "LLGGGL", "LGLLGG",
            "LGGLLG", "LGGGLL", "LGLGLG", "LGLGGL", "LGGLGL",
        };

        /// <summary>
        /// Validate the input and return the full 13-digit code: 12 digits get
        /// the computed check digit appended; 13 digits must carry a correct
        /// check digit. Anything else is rejected.
        /// </summary>
        public static string Normalize(string value)
        {
            foreach (char c in value)
                if (c is < '0' or > '9')
                    throw new FormatException($"Character '{c}' is not valid for EAN-13 (digits only).");

            switch (value.Length)
            {
                case 12:
                    return value + CheckDigit(value);
                case 13:
                    char expected = CheckDigit(value);
                    if (value[12] != expected)
                        throw new FormatException($"EAN-13 check digit mismatch: expected {expected}, got {value[12]}.");
                    return value;
                default:
                    throw new FormatException($"EAN-13 requires 12 or 13 digits, got {value.Length}.");
            }
        }

        // Check digit over the first 12 digits: odd positions ×1, even ×3 (1-based).
        private static char CheckDigit(string digits)
        {
            int sum = 0;
            for (int i = 0; i < 12; i++)
                sum += (digits[i] - '0') * (i % 2 == 0 ? 1 : 3);
            return (char)('0' + (10 - sum % 10) % 10);
        }

        /// <summary>
        /// Encode a normalized 13-digit code and return the raw module bits
        /// (always 95): true = bar, false = space.
        /// </summary>
        public static bool[] Encode(string digits13)
        {
            var bits = new List<bool>(95);
            Append(bits, "101"); // start guard

            string parity = LeftParity[digits13[0] - '0'];
            for (int i = 0; i < 6; i++)
            {
                int d = digits13[i + 1] - '0';
                Append(bits, parity[i] == 'L' ? LCodes[d] : GCodes[d]);
            }

            Append(bits, "01010"); // center guard

            for (int i = 0; i < 6; i++)
                Append(bits, RCodes[digits13[i + 7] - '0']);

            Append(bits, "101"); // end guard
            return bits.ToArray();
        }

        private static void Append(List<bool> bits, string pattern)
        {
            foreach (char bit in pattern)
                bits.Add(bit == '1');
        }
    }
}
